customCss:
/* Dyslexia readability tweaks */
:root {
  --dyslexia-word-spacing: 3px;
  --dyslexia-letter-spacing: 0.25px;
  --dyslexia-line-height: 2;
}

/* Apply spacing to all text */
body, textarea, input, button, select, .messageContent-3q2W1t, .markup-2BOw-j {
  word-spacing: var(--dyslexia-word-spacing) !important;
  letter-spacing: var(--dyslexia-letter-spacing) !important;
}

/* Message line height */
.messageContent-3q2W1t, .contents-2mQqc9 {
  line-height: var(--dyslexia-line-height) !important;
}

/* Slightly larger timestamps & reduce visual clutter */
.timestamp-3ZCmNB, time {
  font-size: 0.9rem !important;
}

/* Better contrast for dyslexia */
.textArea-12jDsm {
  background-color: rgba(0,0,0,0.3) !important;
}
